    (gen_random_uuid(), 'GRUPO NORTEMPO EMPRESA DE TRABAJO TEMPORAL, S.A.', 'Certification', 'Esquema Nacional de Seguridad', 0, 'ISO 27001/27701 + auditoría de recertificación (si aplica) | ISO 22301 (continuidad) + BIA/DRP | Evaluaciones técnicas: pentest/vulnerabilidades (a validar con portfolio)', NULL, NULL, NULL, NULL, NULL, NULL),
    (gen_random_uuid(), 'GRUPO PRISA', 'ESG Solutions', 'Sustainability Report Assurance', 0, 'Programa anual de aseguramiento ESG (alcance ampliado) | Verificación huella de carbono (org/producto) (a validar) | Auditorías a proveedores (2ª parte) para cadena de suministro', NULL, NULL, NULL, 3, '“Ya que hacemos aseguramiento del informe, podemos ampliar a un programa anual de assurance (procesos + KPIs) y complementar con ciber/privacidad y continuidad para reforzar el control interno y la confianza externa. ¿Lo vemos en una sesión de 30 min?”', '1) ¿Qué KPIs/materialidad son más sensibles para inversores/mercado? 2) ¿Qué parte del dato ESG os cuesta más (captura, trazabilidad, evidencias)? 3) ¿Queréis ampliar el alcance del assurance (más KPIs/entidades)? 4) ¿Tenéis iniciativas de ISO 27001/privacidad o continuidad ya en marcha? 5) ¿Quién es el owner del reporting ESG y quién de IT/riesgos?'),
    (gen_random_uuid(), 'ATEOS ARQUITECTURA TÉCNICA, S.L.', 'Certification', 'ISO 9001:2015', 2, 'ISO 14001 (medio ambiente) + integración | ISO 45001 (SST) + integración | Auditorías 2ª parte a proveedores / homologación', NULL, NULL, NULL, NULL, NULL, NULL),
    (gen_random_uuid(), 'BIOSEARCH, S.A.U.', 'Certification', 'ISO 14001:2015', 0, 'ISO 50001 (energía) / optimización | Huella de carbono + verificación (a validar) | Auditorías de compliance ambiental (a validar)', NULL, NULL, NULL, 6, '“Podemos construir sobre 14001 un plan muy práctico: ISO 50001 para eficiencia y, si interesa, huella/verificación para reforzar credenciales en clientes. Además, auditorías 2ª parte a proveedores críticos suelen reducir riesgos de calidad/compliance.”', '1) ¿Tenéis objetivos de energía/emisiones por planta o corporativos? 2) ¿Qué clientes os piden evidencias ESG (huella, claims, auditorías)? 3) ¿Quiénes son proveedores críticos (materias primas, packaging, logística)? 4) ¿Tenéis auditorías de proveedores hoy? ¿Con qué criterios? 5) ¿Qué iniciativas internas de eficiencia energética tenéis en curso?'),
    (gen_random_uuid(), 'HEIDELBERG MATERIALS HISPANIA ÁRIDOS, S.A.', 'Certification', 'ISO 14001:2015', 0, 'ISO 50001 (energía) / optimización | Huella de carbono + verificación (a validar) | Auditorías de compliance ambiental (a validar)', NULL, NULL, NULL, 5, '“Con 14001 activo, el siguiente ROI típico es ISO 50001 + verificación de huella (si hay reporting/licitaciones) y, donde aplica, programas de inspección/ensayo para control operativo. Proponemos piloto en 1–2 centros de mayor consumo.”', '1) ¿Qué centros concentran consumo energético/emisiones? 2) ¿Tenéis objetivos corporativos de descarbonización/reporting? 3) ¿Qué peso tienen licitaciones/cliente industrial en el negocio? 4) ¿Tenéis sistema de mantenimiento/inspección estandarizado entre centros? 5) ¿Qué KPIs ambientales son críticos (combustibles, polvo, ruido, agua)?'),
    (gen_random_uuid(), 'PATATAS HIJOLUSA, S.A.U.', 'Certification', 'GLOBALGAP COC', 0, 'Extensión multi-site / alcance cadena de custodia | Auditorías 2ª parte a proveedores (calidad/food safety) | Ensayos laboratorio (micro/residuos) (a validar)', NULL, NULL, NULL, NULL, NULL, NULL),
    (gen_random_uuid(), 'PORTOSIN FISS, S.A.U.', 'Certification', 'MSC/ASC/MSC DS MULTISITE', 0, 'Extensión multi-site / alcance cadena de custodia | Auditorías 2ª parte a proveedores (calidad/food safety) | Ensayos laboratorio (micro/residuos) (a validar)', NULL, NULL, NULL, NULL, NULL, NULL),
    (gen_random_uuid(), 'FUNDACIÓN HOSPITAL NACIONAL DE PARAPLÉJICOS PARA LA INVESTIGACIÓN Y LA INTEGRACIÓN', 'ESG Solutions', 'DNSH', 0, 'Aseguramiento ESG/DNSH para proyectos recurrentes | Verificación de indicadores y evidencias (a validar) | Formación/compliance de sostenibilidad para PMO', NULL, NULL, NULL, NULL, NULL, NULL),
    (gen_random_uuid(), 'LECTA GROUP', 'Certification', 'Customized Technical Consulting', 0, 'Auditoría/diagnóstico para identificar gaps y roadmap | Formación (auditor interno / compliance) | Auditorías 2ª parte a proveedores/contratas', NULL, NULL, NULL, 9, '“Si ya habéis contado con consultoría, podemos dar el siguiente paso hacia un esquema certificable y repetible (ISO integradas) y añadir, cuando convenga, verificación de huella/claims. Proponemos una sesión para mapear plantas y priorizar quick wins.”', '1) ¿Qué plantas/centros en España entran en alcance? 2) ¿Qué pide el cliente: CoC (FSC/PEFC), huella, EPD, auditorías? 3) ¿Dónde están los mayores costes/riesgos: energía, químicos, residuos? 4) ¿Qué madurez tenéis hoy en sistemas ISO (existentes/anteriores)? 5) ¿Buscáis un modelo multi-site para reducir coste de auditoría?'),
    (gen_random_uuid(), 'DANOSA GROUP, S.A.', 'Certification', 'IDI Proyectos', 0, 'Auditoría/diagnóstico para identificar gaps y roadmap | Formación (auditor interno / compliance) | Auditorías 2ª parte a proveedores/contratas', NULL, NULL, NULL, 8, '“Podemos ayudaros a estructurar un roadmap de certificación y aseguramiento (ISO 9001/14001/45001 si aplica) y complementarlo con verificación de claims/indicadores cuando lo pidan clientes. Empezaría con un diagnóstico de situación y objetivos por línea de producto.”', '1) ¿Qué mercados/canales pesan más (obra pública, industrial, rehab)? 2) ¿Qué requisitos os piden clientes (ISO, EPD/huella, ensayos)? 3) ¿Tenéis un sistema de gestión corporativo o por planta? 4) ¿Qué líneas/productos generan más no conformidades o reclamaciones? 5) ¿Quién lidera calidad/I+D y quién compras/proveedores?'),
    (gen_random_uuid(), 'GES SEGUROS Y REASEGUROS, S.A.', 'Certification', 'IDI Proyectos', 0, 'Auditoría/diagnóstico para identificar gaps y roadmap | Formación (auditor interno / compliance) | Auditorías 2ª parte a proveedores/contratas', NULL, NULL, NULL, 10, '“En aseguradoras suele funcionar muy bien un paquete de ISO 27001/27701 + ISO 22301 (según madurez) y evaluaciones técnicas para reforzar la gestión del riesgo. Podemos hacer un gap assessment rápido y definir roadmap y esfuerzo.”', '1) ¿Tenéis ISMS formal (27001) o controles parciales? 2) ¿Qué sistemas son críticos (core, siniestros, canales digitales)? 3) ¿Cómo gestionáis continuidad: BIA/DRP, pruebas, RTO/RPO? 4) ¿Tenéis objetivos regulatorios o de cliente que empujen certificación? 5) ¿Quién decide: IT, Riesgos, Cumplimiento o Seguridad?'),
    (gen_random_uuid(), 'DISTRIBUIDORES AUTOMÁTICOS DE BEBIDAS Y ALIMENTOS S.L.', 'Second Party', 'CXM Process Audits', 0, 'Auditoría/diagnóstico para identificar gaps y roadmap | Formación (auditor interno / compliance) | Auditorías 2ª parte a proveedores/contratas', NULL, NULL, NULL, NULL, NULL, NULL),
