    (gen_random_uuid(), 'CLÍNICA DENTAL VITA, S.L.', 'Medical Devices', 'ISO 13485:2016', 0, 'Auditorías 2ª parte a proveedores críticos (sanitario) | Ensayos/validaciones de producto/proceso (a definir) | ISO 14001/45001 (sistemas de soporte) si aplica', NULL, NULL, NULL, NULL, NULL, NULL),
    (gen_random_uuid(), '720 TEC, S.L.', 'Certification', 'ISO/IEC 27001:2022', 0, 'ISO 27701 (privacidad) / extensión ISMS | ISO 22301 (continuidad) / ejercicios | Evaluaciones técnicas: pentest/vulnerabilidades (a validar con portfolio)', NULL, NULL, NULL, NULL, NULL, NULL),
    (gen_random_uuid(), 'NOATUM (NOATUM LOGISTICS SPAIN, S.L.U.)', 'Certification', 'RBS Social', 0, 'Auditorías 2ª parte a proveedores (social/ética) escaladas | Aseguramiento ESG / claims y KPIs (a validar) | Programas de trazabilidad y riesgo supply chain (a validar)', NULL, NULL, NULL, NULL, NULL, NULL),
    (gen_random_uuid(), 'ALCAMPO, S.A.U.', 'Certification', 'RBS Social', 0, 'Auditorías 2ª parte a proveedores (social/ética) escaladas | Aseguramiento ESG / claims y KPIs (a validar) | Programas de trazabilidad y riesgo supply chain (a validar)', NULL, NULL, NULL, 1, '“Viendo que ya trabajáis auditoría social, podemos ayudaros a convertirlo en un programa recurrente de auditorías a proveedores por riesgo (país/categoría) y, además, asegurar claims/indicadores ESG con evidencias auditables. ¿Tenéis 20 min para ver cómo priorizar el piloto?”', '1) ¿Qué categorías/proveedores son más críticos (volumen/riesgo/país)? 2) ¿Cómo decidís hoy la muestra y periodicidad de auditorías? 3) ¿Qué pain tenéis: CAPAs lentas, falta de visibilidad Tier-2, incidencias? 4) ¿Qué KPIs/claims ESG queréis “blindar” (alcances, packaging, deforestación, etc.)? 5) ¿Quién lidera esto: Compras, RSC/ESG o Calidad?'),
    (gen_random_uuid(), 'IBERDROLA ESPAÑA, S.A.U.', 'Certification', 'RBS Social', 0, 'Auditorías 2ª parte a proveedores (social/ética) escaladas | Aseguramiento ESG / claims y KPIs (a validar) | Programas de trazabilidad y riesgo supply chain (a validar)', NULL, NULL, NULL, 2, '“Si ya estáis auditando socialmente, el siguiente salto de valor suele ser un modelo de Supplier Assurance integral (social + ambiental + compliance) y, cuando aplica, aseguramiento ESG de KPIs críticos. Podemos proponeros un piloto por familias de compra y geografía.”', '1) ¿Qué familias de compra tienen mayor riesgo (contratas, equipos críticos, servicios)? 2) ¿Tenéis segmentación de proveedores por criticidad/riesgo? 3) ¿Qué KPIs de compras responsables reportáis y cuáles os gustaría asegurar? 4) ¿Cómo gestionáis CAPAs y reincidencias hoy? 5) ¿Os interesa un enfoque multi-país o España primero?'),
