    (gen_random_uuid(), 'El Corte Inglés', NULL, 'Auditoría social (RBS Social)', NULL, '1) ESG/aseguramiento y verificación de reporting 2) Digital Trust (ISO 27001/27701, pentest) 3) Auditorías cadena de suministro (2ª parte)', 'Retail / distribución', 'Riesgos citados públicamente: ciber + objetivos sostenibilidad en financiación', 'Alta', NULL, NULL, NULL),
    (gen_random_uuid(), 'El Encinar de Humienta', NULL, '“IDI Proyectos”', NULL, '1) Food Safety (ISO 22000/FSSC 22000/BRCGS/IFS – a confirmar cuál aplica) 2) Ensayos/microbiología 3) Auditorías a proveedores + trazabilidad', 'Cárnico / alimentación', 'Actividad cárnica y calidad', 'Media-Alta', NULL, NULL, NULL),
