    (gen_random_uuid(), 'Autocares Vázquez Olmedo (AVO Group)', NULL, 'ISO 9001/14001/45001/50001? + EMAS + ISO 39001 + UNE 13816…', NULL, '1) Huella carbono/verificación + ESG 2) Digital Trust básico (ISO 27001) 3) Programas de formación (SST, auditor interno, seguridad vial)', 'Transporte viajeros', 'Mucha base de sistemas; fácil ampliar a ESG/ciber', 'Media', NULL, NULL, NULL),
